// Ghost post.published payload shape (per Ghost docs):
//   { post: { current: { id, title, url, primary_author: { name }, excerpt, published_at }, previous: {...} } }
//
// Handle both the wrapped-under-'body' shape (n8n webhook default) and
// the direct payload shape (in case Ghost is proxied through something
// that strips the wrapper).

const body = $input.first().json.body || $input.first().json;
const current = body?.post?.current || {};

const title    = current.title || '(untitled)';
const url      = current.url || '';
const author   = current.primary_author?.name || 'Unknown author';
const excerpt  = current.excerpt || '';
const postedAt = current.published_at || new Date().toISOString();
const postId   = current.id || '';

// Compact message for Mattermost. Keeps the excerpt to one paragraph.
const message = [
  `:pencil2: **New post published** — *${title}*`,
  `by **${author}** · ${postedAt}`,
  '',
  excerpt ? `> ${excerpt.replace(/\n/g, ' ').slice(0, 240)}${excerpt.length > 240 ? '…' : ''}` : '',
  url ? `[Read →](${url})` : ''
].filter(Boolean).join('\n');

return [{ json: { message, postId, title, url, author } }];
